stages.example:
- stage: extract
  args:
    - { selector: "h1", method: "text", as: "title" }
    - { selector: "span.price", method: "price", as: "price_numeric" }

- stage: load_csv
  args:
    - { path: "s3a://bucket/input.csv", header: "true", inferSchema: "true" }

- stage: load_union
  args:
    - { format: "csv", path: "s3a://bucket/a.csv", options: { header: "true" } }
    - { format: "csv", path: "s3a://bucket/b.csv", options: { header: "true" } }

- stage: load_mongodb
  args:
    - { uri: "mongodb://host:27017", database: "mydb", collection: "products" }

- stage: enrichMatchingScore
  args:
    - { ean_field: "EAN number", extracted_prefix: "prod_", output_field: "matching_score" }

- stage: propertyCluster
  args:
    - { algorithm: "kmeans", k: 5, features: ["latitude", "longitude", "price_per_sqm"] }

- stage: propertyClusterML
  args:
    - { algorithm: "gmm", k: 4, features: ["price_per_sqm", "area_sqm"] }
